import requests
import json
import logging


class LoggingFlask:

    def __init__(self):
        self.logger = logging.getLogger(__name__)

        # configure file handler
        self.fh = logging.FileHandler("flask_log.txt")
        self.fh.setLevel(logging.DEBUG)
        formatter = logging.Formatter('%(asctime)s - %(levelname)s \
              - %(funcName)s: - %(message)s')

        # configure console handler for logging
        self.ch = logging.StreamHandler()
        self.ch.setLevel(logging.DEBUG)
        self.ch.setFormatter(formatter)

    def get_logger(self):
         return self.logger
    def addHandlersToLogger(self, logger):
        logger.addHandler(self.fh)
        logger.addHandler(self.ch)



class AuthToken:

    def __init__(self):

        self.auth = ("<PASSWORD>", "<PASSWORD>")

    # configure logger object with the log object
    flask_log = LoggingFlask()
    flask_log.get_logger().setLevel(logging.DEBUG)
    flask_log.addHandlersToLogger(flask_log.get_logger())

api_url = 'https://httpbin.org/post'


def login():

    try:

        authToken = AuthToken()
        reqHeader = {
            "Authorization": f"Bearer {authToken.auth[0]}",
            }
        login_data = json.dumps({
            'email': '<EMAIL>',
            'password':'<PASSWORD>',
            })
        
        # send POST request to api
        response = requests.post(url=api_url, headers=reqHeader, data=login_data)

        # logging API response and error messages. 
        # The status codes in the response object are not included as there is an open issue on GitHub.
        if (response):
            flask_log.get_logger().info('201 Created')
            return True
        else: 
            flask_log.get_logger().error(f'{response}')
            return False

    except Exception as e:

        print("Exception raised: ",e)
        flask_log.get_logger().debug(f'The following exception was raised: {e}')